export function useExternalDrop({
  dataRef,
  pendingOpsRef,
  selectedTrackId,

import { useCallback } from 'react';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getNextClipId, type ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type {
  TimelineApplyEdit,
  TimelineDataRef,
  TimelinePatchRegistry,
  TimelineRegisterAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';
import type { ShotFinalVideo } from '@/tools/video-editor/hooks/useFinalVideoAvailable';
import type { AssetRegistryEntry, PinnedShotGroup, PinnedShotImageClipSnapshot } from '@/tools/video-editor/types';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

interface UseSwitchToFinalVideoArgs {
  applyEdit: TimelineApplyEdit;
  dataRef: TimelineDataRef;
  finalVideoMap: Map<string, ShotFinalVideo>;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
}

function getClipDuration(meta: ClipMeta, action: TimelineAction): number {
  if (typeof meta.hold === 'number' && Number.isFinite(meta.hold) && meta.hold > 0) {
    return meta.hold;
  }

  if (
    typeof meta.from === 'number'
    && typeof meta.to === 'number'
    && Number.isFinite(meta.from)
    && Number.isFinite(meta.to)
    && meta.to > meta.from
  ) {
    return Math.max(0.05, (meta.to - meta.from) / Math.max(meta.speed ?? 1, 0.01));
  }

  return Math.max(0.05, action.end - action.start);
}

function snapshotClipMeta(meta: ClipMeta): PinnedShotImageClipSnapshot['meta'] {
  return {
    clipType: meta.clipType,
    from: meta.from,
    to: meta.to,
    speed: meta.speed,
    hold: meta.hold,
    volume: meta.volume,
    x: meta.x,
    y: meta.y,
    width: meta.width,
    height: meta.height,
    cropTop: meta.cropTop,
    cropBottom: meta.cropBottom,
    cropLeft: meta.cropLeft,
    cropRight: meta.cropRight,
    opacity: meta.opacity,
    text: meta.text,
    entrance: meta.entrance,
    exit: meta.exit,
    continuous: meta.continuous,
    transition: meta.transition,
    effects: meta.effects,
  };
}

function replacePinnedGroup(
  pinnedShotGroups: NonNullable<PinnedShotGroup[]>,
  nextGroup: PinnedShotGroup,
  fallbackShotId: string,
  fallbackTrackId: string,
) {
  const existingIndex = pinnedShotGroups.findIndex((group) => (
    group.shotId === fallbackShotId
    && group.trackId === fallbackTrackId
  ));

  if (existingIndex < 0) {
    return [...pinnedShotGroups, nextGroup];
  }

  return pinnedShotGroups.map((group, index) => (index === existingIndex ? nextGroup : group));
}

function registerFinalVideoAsset(
  finalVideo: ShotFinalVideo,
  patchRegistry: TimelinePatchRegistry,
  registerAsset: TimelineRegisterAsset,
): string {
  const assetKey = generateUUID();
  const assetEntry: AssetRegistryEntry = {
    file: finalVideo.location,
    type: 'video/mp4',
    generationId: finalVideo.id,
  };
  patchRegistry(assetKey, assetEntry, finalVideo.location);
  void registerAsset(assetKey, assetEntry).catch((error) => {
    console.error('[TimelineEditor] Failed to persist final video asset:', error);
  });
  return assetKey;
}

export function useSwitchToFinalVideo({
  applyEdit,
  dataRef,
  finalVideoMap,
  patchRegistry,
  registerAsset,
}: UseSwitchToFinalVideoArgs) {
  const switchToFinalVideo = useCallback(({ shotId, clipIds, rowId }: { shotId: string; clipIds: string[]; rowId: string }) => {
    const finalVideo = finalVideoMap.get(shotId);
    const current = dataRef.current;
    if (!finalVideo || !current || clipIds.length === 0 || !current.rows.some((row) => row.id === rowId)) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => group.shotId === shotId && group.trackId === rowId);
    const sourceClipIds = pinnedGroup?.mode === 'images'
      ? pinnedGroup.clipIds
      : clipIds;
    const clipIdSet = new Set(sourceClipIds);
    const targetRow = current.rows.find((row) => row.id === rowId);
    if (!targetRow) {
      return;
    }

    const imageActions = targetRow.actions.filter((action) => clipIdSet.has(action.id));
    if (imageActions.length !== sourceClipIds.length) {
      return;
    }

    const startTime = Math.min(...imageActions.map((action) => action.start));
    const endTime = Math.max(...imageActions.map((action) => action.end));
    if (!Number.isFinite(startTime) || !Number.isFinite(endTime) || endTime <= startTime) {
      return;
    }

    const imageClipSnapshot = sourceClipIds.flatMap((sourceClipId) => {
      const sourceMeta = current.meta[sourceClipId];
      if (!sourceMeta) {
        return [];
      }

      return [{
        clipId: sourceClipId,
        assetKey: sourceMeta.asset,
        meta: snapshotClipMeta(sourceMeta),
      }];
    });
    if (imageClipSnapshot.length !== sourceClipIds.length) {
      return;
    }

    const assetKey = registerFinalVideoAsset(finalVideo, patchRegistry, registerAsset);

    const videoClipId = getNextClipId(current.meta);
    const targetTrack = current.tracks.find((track) => track.id === rowId);
    const isManualVisualTrack = targetTrack?.kind === 'visual' && targetTrack.fit === 'manual';
    const videoMeta: ClipMeta = {
      asset: assetKey,
      track: rowId,
      clipType: 'media',
      from: 0,
      to: endTime - startTime,
      speed: 1,
      volume: 1,
      opacity: 1,
      x: isManualVisualTrack ? 100 : undefined,
      y: isManualVisualTrack ? 100 : undefined,
      width: isManualVisualTrack ? 320 : undefined,
      height: isManualVisualTrack ? 240 : undefined,
    };
    const videoAction: TimelineAction = {
      id: videoClipId,
      start: startTime,
      end: endTime,
      effectId: `effect-${videoClipId}`,
    };

    const insertionIndex = targetRow.actions.findIndex((action) => clipIdSet.has(action.id));
    const nextRows = current.rows.map((row) => {
      const remainingActions = row.actions.filter((action) => !clipIdSet.has(action.id));
      if (row.id !== rowId) {
        return remainingActions.length === row.actions.length ? row : { ...row, actions: remainingActions };
      }

      const nextActions = insertionIndex < 0
        ? [...remainingActions, videoAction]
        : [...remainingActions.slice(0, insertionIndex), videoAction, ...remainingActions.slice(insertionIndex)];
      return { ...row, actions: nextActions };
    });
    const nextClipOrder = updateClipOrder(current.clipOrder, rowId, (ids) => {
      const filtered = ids.filter((id) => !clipIdSet.has(id));
      const orderInsertionIndex = ids.findIndex((id) => clipIdSet.has(id));
      return orderInsertionIndex < 0
        ? [...filtered, videoClipId]
        : [...filtered.slice(0, orderInsertionIndex), videoClipId, ...filtered.slice(orderInsertionIndex)];
    });

    const nextPinnedShotGroups = replacePinnedGroup(
      existingPinnedGroups,
      {
        shotId,
        trackId: rowId,
        clipIds: [videoClipId],
        mode: 'video',
        videoAssetKey: assetKey,
        imageClipSnapshot,
      },
      shotId,
      rowId,
    );

    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: { [videoClipId]: videoMeta },
      metaDeletes: sourceClipIds,
      clipOrderOverride: nextClipOrder,
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef, finalVideoMap, patchRegistry, registerAsset]);

  const updateToLatestVideo = useCallback(({ shotId, rowId }: { shotId: string; rowId: string }) => {
    const current = dataRef.current;
    const finalVideo = finalVideoMap.get(shotId);
    if (!current || !finalVideo) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
      && group.mode === 'video'
      && typeof group.videoAssetKey === 'string'
      && group.videoAssetKey.length > 0
    ));
    const videoClipId = pinnedGroup?.clipIds[0];
    const targetRow = current.rows.find((row) => row.id === rowId);
    const videoAction = videoClipId ? targetRow?.actions.find((action) => action.id === videoClipId) : undefined;
    const videoMeta = videoClipId ? current.meta[videoClipId] : undefined;
    const currentGenerationId = pinnedGroup?.videoAssetKey
      ? current.registry.assets[pinnedGroup.videoAssetKey]?.generationId
      : undefined;
    if (!pinnedGroup || !videoClipId || !videoAction || !videoMeta || currentGenerationId === finalVideo.id) {
      return;
    }

    const assetKey = registerFinalVideoAsset(finalVideo, patchRegistry, registerAsset);
    const nextPinnedShotGroups = replacePinnedGroup(
      existingPinnedGroups,
      {
        ...pinnedGroup,
        videoAssetKey: assetKey,
      },
      shotId,
      rowId,
    );

    applyEdit({
      type: 'rows',
      rows: current.rows,
      metaUpdates: {
        [videoClipId]: {
          asset: assetKey,
        },
      },
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef, finalVideoMap, patchRegistry, registerAsset]);

  const switchToImages = useCallback(({ shotId, rowId }: { shotId: string; rowId: string }) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
      && group.mode === 'video'
    ));
    const targetRow = current.rows.find((row) => row.id === rowId);
    const videoClipId = pinnedGroup?.clipIds[0];
    const videoActionIndex = targetRow?.actions.findIndex((action) => action.id === videoClipId) ?? -1;
    const videoAction = videoActionIndex >= 0 ? targetRow?.actions[videoActionIndex] : undefined;
    if (!pinnedGroup || !targetRow || !videoClipId || !videoAction || !pinnedGroup.imageClipSnapshot?.length) {
      return;
    }

    const restoredMetaUpdates: Record<string, ClipMeta> = {};
    let cursor = videoAction.start;
    const restoredActions = pinnedGroup.imageClipSnapshot.map((snapshot) => {
      const clipMeta: ClipMeta = {
        ...snapshot.meta,
        asset: snapshot.assetKey,
        track: rowId,
      };
      restoredMetaUpdates[snapshot.clipId] = clipMeta;
      const duration = getClipDuration(clipMeta, videoAction);
      const action: TimelineAction = {
        id: snapshot.clipId,
        start: cursor,
        end: cursor + duration,
        effectId: `effect-${snapshot.clipId}`,
      };
      cursor = action.end;
      return action;
    });

    const nextRows = current.rows.map((row) => {
      if (row.id !== rowId) {
        return row;
      }

      const remainingActions = row.actions.filter((action) => action.id !== videoClipId);
      return {
        ...row,
        actions: [
          ...remainingActions.slice(0, videoActionIndex),
          ...restoredActions,
          ...remainingActions.slice(videoActionIndex),
        ],
      };
    });
    const nextClipOrder = updateClipOrder(current.clipOrder, rowId, (ids) => {
      const filtered = ids.filter((id) => id !== videoClipId);
      const insertionIndex = ids.indexOf(videoClipId);
      const restoredClipIds = pinnedGroup.imageClipSnapshot?.map((snapshot) => snapshot.clipId) ?? [];
      return insertionIndex < 0
        ? [...filtered, ...restoredClipIds]
        : [...filtered.slice(0, insertionIndex), ...restoredClipIds, ...filtered.slice(insertionIndex)];
    });
    const nextPinnedShotGroups = replacePinnedGroup(
      existingPinnedGroups,
      {
        ...pinnedGroup,
        clipIds: pinnedGroup.imageClipSnapshot.map((snapshot) => snapshot.clipId),
        mode: 'images',
        videoAssetKey: undefined,
      },
      shotId,
      rowId,
    );

    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: restoredMetaUpdates,
      metaDeletes: [videoClipId],
      clipOrderOverride: nextClipOrder,
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef]);

  return {
    switchToFinalVideo,
    updateToLatestVideo,
    switchToImages,
  };
}

/**
 * useShotFinalVideos - Batch-fetches the latest final video for each shot in a project.
 *
 * Returns a map of shotId → ShotFinalVideo for shots that have
 * a completed final video. Used by the shot list to show video previews.
 */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { finalVideoQueryKeys } from '@/shared/lib/queryKeys/finalVideos';

export interface ShotFinalVideo {
  id: string;
  location: string;
  thumbnailUrl: string | null;
}

export function useShotFinalVideos(projectId: string | null) {
  const { data: rawData, isLoading } = useQuery({
    queryKey: finalVideoQueryKeys.byProject(projectId!),
    queryFn: async () => {
      const { data, error } = await supabase().from('shot_final_videos')
        .select('id, location, thumbnail_url, shot_id, created_at')
        .eq('project_id', projectId!)
        .not('location', 'is', null)
        .order('created_at', { ascending: false });

      if (error) {
        console.error('[useShotFinalVideos] Error:', error);
        return [];
      }
      return data || [];
    },
    enabled: !!projectId,
    staleTime: 30_000,
  });

  // Build map: shotId → latest final video (first per shot since ordered by created_at desc)
  const finalVideoMap = useMemo(() => {
    const map = new Map<string, ShotFinalVideo>();
    if (!rawData) return map;

    for (const row of rawData) {
      const shotId = typeof (row as Record<string, unknown>).shot_id === 'string'
        ? (row as Record<string, unknown>).shot_id as string
        : null;
      const location = typeof row.location === 'string' ? row.location : null;
      const id = typeof row.id === 'string' ? row.id : null;

      if (shotId && id && location && !map.has(shotId)) {
        map.set(shotId, {
          id,
          location,
          thumbnailUrl: row.thumbnail_url || null,
        });
      }
    }
    return map;
  }, [rawData]);

  return { finalVideoMap, isLoading };
}

/**
 * Shared utilities for drag-and-drop operations involving generations and shots
 *
 * Used by:
 * - MediaGalleryItem (drag source)
 * - ShotGroup, SortableShotItem, ShotListDisplay (drop targets)
 * - Timeline components (drop targets)
 * - BatchDropZone (drop target)
 */

import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';

// MIME type for generation drag data
const GENERATION_MIME_TYPE = 'application/x-generation';
const GENERATION_TEXT_PREFIX = '__reigh_generation__:';
export const GENERATION_MULTI_DRAG_TYPE = 'application/x-generation-multi';
const GENERATION_MULTI_TEXT_PREFIX = '__reigh_generation_multi__:';
const SHOT_MIME_TYPE = 'application/x-shot';
const SHOT_TEXT_PREFIX = '__reigh_shot__:';

// Droppable ID for creating a new shot from a dropped generation
export const NEW_GROUP_DROPPABLE_ID = 'new-shot-group-dropzone';

/**
 * Cross-browser safe check for whether a DataTransfer contains a type.
 */
function hasDataTransferType(dataTransfer: DataTransfer, type: string): boolean {
  const types = dataTransfer?.types;
  if (!types) return false;

  if (typeof types.includes === 'function') {
    try {
      return !!types.includes(type);
    } catch {
      // ignore
    }
  }

  const length = typeof types.length === 'number' ? types.length : 0;
  for (let i = 0; i < length; i += 1) {
    if (types[i] === type) return true;
  }

  return false;
}

/**
 * Data structure for dragging generations between components
 */
export interface GenerationDropData {
  generationId: string;
  variantId?: string;
  variantType?: string;
  imageUrl: string;
  thumbUrl?: string;
  metadata?: Record<string, unknown>;
}

export interface ShotDropData {
  shotId: string;
  shotName: string;
  imageGenerationIds: string[];
}

/**
 * Type of drag operation
 */
export type DragType = 'generation' | 'generation-multi' | 'shot' | 'file' | 'none';

function isMultiGenerationDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, GENERATION_MULTI_DRAG_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseMultiGenerationDropData(textPayload) !== null;
}

/**
 * Check if the drag event contains generation data.
 * @internal Used by getDragType.
 */
function isGenerationDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, GENERATION_MIME_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseGenerationDropData(textPayload) !== null;
}

function isShotDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, SHOT_MIME_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseShotDropData(textPayload) !== null;
}

/**
 * Check if the drag event contains files
 */
export function isFileDrag(e: React.DragEvent): boolean {
  return hasDataTransferType(e.dataTransfer, 'Files');
}

/**
 * Determine the type of drag operation
 */
export function getDragType(e: React.DragEvent): DragType {
  if (isMultiGenerationDrag(e)) return 'generation-multi';
  if (isGenerationDrag(e)) return 'generation';
  if (isShotDrag(e)) return 'shot';
  if (isFileDrag(e)) return 'file';
  return 'none';
}

/**
 * Set generation drag data on the dataTransfer object
 * Call this in onDragStart
 */
export function setGenerationDragData(e: React.DragEvent, data: GenerationDropData): void {
  const serialized = JSON.stringify(data);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(GENERATION_MIME_TYPE, serialized);
  // Fallback: some browsers/targets are inconsistent about exposing custom MIME types during dragover.
  try {
    e.dataTransfer.setData('text/plain', `${GENERATION_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

export function setMultiGenerationDragData(
  e: React.DragEvent,
  items: GenerationDropData[],
): void {
  const serialized = JSON.stringify(items);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(GENERATION_MULTI_DRAG_TYPE, serialized);
  try {
    e.dataTransfer.setData('text/plain', `${GENERATION_MULTI_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

export function setShotDragData(e: React.DragEvent, data: ShotDropData): void {
  const serialized = JSON.stringify(data);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(SHOT_MIME_TYPE, serialized);
  try {
    e.dataTransfer.setData('text/plain', `${SHOT_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

function parseGenerationDropData(dataString: string): GenerationDropData | null {
  if (!dataString) {
    return null;
  }

  let data: GenerationDropData;
  try {
    const normalized = dataString.startsWith(GENERATION_TEXT_PREFIX)
      ? dataString.slice(GENERATION_TEXT_PREFIX.length)
      : dataString;
    data = JSON.parse(normalized) as GenerationDropData;
  } catch {
    return null;
  }

  if (!data.generationId || !data.imageUrl) {
    return null;
  }

  return data;
}

function parseMultiGenerationDropData(dataString: string): GenerationDropData[] | null {
  if (!dataString) {
    return null;
  }

  let data: unknown;
  try {
    const normalized = dataString.startsWith(GENERATION_MULTI_TEXT_PREFIX)
      ? dataString.slice(GENERATION_MULTI_TEXT_PREFIX.length)
      : dataString;
    data = JSON.parse(normalized);
  } catch {
    return null;
  }

  if (!Array.isArray(data) || data.length === 0) {
    return null;
  }

  const items = data
    .map((item) => parseGenerationDropData(JSON.stringify(item)))
    .filter((item): item is GenerationDropData => item !== null);

  return items.length === data.length ? items : null;
}

function parseShotDropData(dataString: string): ShotDropData | null {

  selectedTrackId,
  applyEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  coordinator,
  registerGenerationAsset,
  uploadImageGeneration,
  handleAssetDrop: dropAsset,
  handleAddTextAt,
  onSeekToTime,
}: UseExternalDropArgs): UseExternalDropResult {
  const { shots } = useShots();
  const externalDragFrameRef = useRef<number | null>(null);
  const autoScrollerRef = useRef<ReturnType<typeof createAutoScroller> | null>(null);
  const latestExternalDragRef = useRef<{
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
  } | null>(null);
  const latestExternalPositionRef = useRef<ReturnType<DragCoordinator['update']> | null>(null);

  const clearExternalDragState = useCallback(() => {
    if (externalDragFrameRef.current !== null) {
      window.cancelAnimationFrame(externalDragFrameRef.current);
      externalDragFrameRef.current = null;
    }
    autoScrollerRef.current?.stop();
    autoScrollerRef.current = null;
    latestExternalDragRef.current = null;
    latestExternalPositionRef.current = null;
    coordinator.end();
  }, [coordinator]);

  useEffect(() => {
    return () => {
      clearExternalDragState();
    };
  }, [clearExternalDragState]);

  const onTimelineDragOver = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    const dragType = getDragType(event);
    const types = Array.from(event.dataTransfer.types);
    if (!types.includes('asset-key')
      && !types.includes('text-tool')
      && !types.includes('effect-layer')
      && dragType !== 'file'
      && dragType !== 'shot'
      && !isGenerationDragType(dragType)) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    event.currentTarget.dataset.dragOver = 'true';
    latestExternalDragRef.current = {
      clientX: event.clientX,
      clientY: event.clientY,
      sourceKind: inferDragKind(event),
    };
    if (!autoScrollerRef.current && coordinator.editAreaRef.current) {
      autoScrollerRef.current = createAutoScroller(coordinator.editAreaRef.current, (clientX, clientY) => {
        const currentDrag = latestExternalDragRef.current;
        if (!currentDrag) {
          return;
        }

        latestExternalPositionRef.current = coordinator.update({
          clientX,
          clientY,
          sourceKind: currentDrag.sourceKind,
        });
      });
    }
    autoScrollerRef.current?.update(event.clientX, event.clientY);

    if (externalDragFrameRef.current !== null) {
      return;
    }

    externalDragFrameRef.current = window.requestAnimationFrame(() => {
      RafLoopDetector.track('externalDrop');
      externalDragFrameRef.current = null;
      const currentDrag = latestExternalDragRef.current;
      if (!currentDrag) {
        return;
      }

      latestExternalPositionRef.current = coordinator.update({
        clientX: currentDrag.clientX,
        clientY: currentDrag.clientY,
        sourceKind: currentDrag.sourceKind,
      });
    });
  }, [coordinator]);

  const onTimelineDragLeave = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    delete event.currentTarget.dataset.dragOver;
    clearExternalDragState();
  }, [clearExternalDragState]);

  const onTimelineDrop = useCallback(async (event: React.DragEvent<HTMLDivElement>) => {
    const dropPosition = finalizeExternalDrop({
      event,
      coordinator,
      autoScrollerRef,
      externalDragFrameRef,
      latestExternalDragRef,
      latestExternalPositionRef,
    });
    await dispatchTimelineDrop({
      event,
      dataRef,
      pendingOpsRef,
      dropPosition,
      selectedTrackId,
      applyEdit,
      patchRegistry,
      uploadAsset,
      invalidateAssetRegistry,
      resolveAssetUrl,
      registerGenerationAsset,
      uploadImageGeneration,
      dropAsset,
      handleAddTextAt,
      shots,
    });
    onSeekToTime?.(dropPosition.time);
  }, [
    applyEdit,
    coordinator,
    dataRef,
    dropAsset,
    invalidateAssetRegistry,
    pendingOpsRef,
    patchRegistry,
    registerGenerationAsset,
    resolveAssetUrl,
    selectedTrackId,
    shots,
    handleAddTextAt,
    uploadAsset,
    uploadImageGeneration,
  ]);

  return {
    onTimelineDragOver,
    onTimelineDragLeave,
    onTimelineDrop,
  };
}

/**
 * Loose type for objects that might have generation_id and/or id.
 * Use this when dealing with untyped or loosely-typed media objects.
 */
import type { GenerationRow } from '@/domains/generation/types';

interface MaybeHasGenerationId {
  generation_id?: string | null;
  id?: string | null;
  metadata?: Record<string, unknown>;
}

const NON_PRELOADABLE_URL_MARKERS = ['_joined_frame.jpg'] as const;

/**
 * Get the canonical generation ID from a media item.
 * Handles both direct generations (id) and variants (generation_id).
 * Also checks metadata.generation_id for compatibility with various data shapes.
 *
 * Priority: generation_id > metadata.generation_id > id
 *
 * @example
 * // Instead of: (media as unknown).generation_id || media.id
 * const genId = getGenerationId(media);
 */
export function getGenerationId(
  media: MaybeHasGenerationId | null | undefined
): string | null {
  if (!media) return null;
  const metadataGenerationId = typeof media.metadata?.generation_id === 'string'
    ? media.metadata.generation_id
    : null;
  return media.generation_id || metadataGenerationId || media.id || null;
}

/**
 * Centralized preload eligibility contract for URL-based media entries.
 */
export function isPreloadableMediaUrl(url: string | null | undefined): boolean {
  if (!url) {
    return false;
  }

  return !NON_PRELOADABLE_URL_MARKERS.some((marker) => url.includes(marker));
}

/**
 * Media item with various URL properties (normalized across sources)
 */
interface MediaWithUrls {
  location?: string | null;
  url?: string | null;
  thumbnail_url?: string | null;
  thumbUrl?: string | null;
  imageUrl?: string | null;
}

export function getMediaUrl(media: MediaWithUrls | null | undefined): string | undefined {
  if (!media) return undefined;
  return media.location || media.url || media.imageUrl || undefined;
}

export function getThumbnailUrl(media: MediaWithUrls | null | undefined): string | undefined {
  if (!media) return undefined;
  return media.thumbnail_url || media.thumbUrl || undefined;
}

/** Transform a variant to a GenerationRow shape for lightbox display. */
export function variantToGenerationRow(
  media: {
    id: string;
    url: string;
    thumbUrl?: string;
    createdAt?: string;
    starred?: boolean;
    metadata?: { prompt?: string; tool_type?: string; variant_type?: string; generation_id?: string | null };
    generation_id?: string | null;
  },
  mediaType: 'video' | 'image',
): GenerationRow {
  const generationId = getGenerationId(media) ?? media.id;

  return {
    id: media.id,
    generation_id: generationId,
    location: media.url,
    thumbUrl: media.thumbUrl,
    type: mediaType,
    createdAt: media.createdAt,
    params: {
      prompt: media.metadata?.prompt,
      tool_type: media.metadata?.tool_type,
      variant_type: media.metadata?.variant_type,
      variant_id: media.id,
    },
    starred: media.starred ?? false,
  };
}

